from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about an athlete (or related entities) into a fluent, single sentence."""
    if not triples:
        return ""

    # Group triples by subject
    from collections import defaultdict
    subj_map = defaultdict(lambda: defaultdict(list))
    for t in triples:
        subj_map[t.subject][t.predicate].append(t.object)

    def format_date(iso_date: str) -> str:
        """Convert YYYY-MM-DD to a more readable form like 30 May 1996."""
        try:
            parts = iso_date.split("-")
            if len(parts) == 3:
                year, month, day = parts
                import calendar
                month_name = calendar.month_name[int(month)]
                return f"{int(day)} {month_name} {year}"
        except Exception:
            pass
        return iso_date

    def clean_name(name: str) -> tuple[str, str]:
        """Return (cleaned_name, role) extracting role from parenthesis if present."""
        if "(" in name and ")" in name:
            base, role = name.split("(", 1)
            role = role.rstrip(")").strip()
            base = base.strip()
            # common role adjustments
            if role.lower() in ["footballer", "player"]:
                role = "footballer"
            return base, role
        return name, ""

    # Determine primary subjects (those not only appearing as objects)
    all_objects = {t.object for t in triples}
    primary_subjects = [s for s in subj_map.keys() if s not in all_objects]

    def team_extra_info(team_name: str) -> str:
        """Return a short phrase with city/owner info for a team if available."""
        info_parts = []
        team_preds = subj_map.get(team_name, {})
        if "city" in team_preds:
            info_parts.append(f"based in {team_preds['city'][0]}")
        if "owner" in team_preds:
            info_parts.append(f"owned by {team_preds['owner'][0]}")
        if info_parts:
            return " (" + " and ".join(info_parts) + ")"
        return ""

    sentences = []

    for subj in primary_subjects:
        preds = subj_map[subj]
        name, role = clean_name(subj)
        parts = []

        # Birth information
        if "birthDate" in preds:
            bd = format_date(preds["birthDate"][0])
            parts.append(f"was born on {bd}")
        elif "birthYear" in preds:
            parts.append(f"was born in {preds['birthYear'][0]}")
        if "birthPlace" in preds:
            parts.append(f"in {preds['birthPlace'][0]}")

        # Physical attributes
        if "height" in preds:
            parts.append(f"is {preds['height'][0]} meters tall")
        if "weight" in preds:
            # Clean weight string
            w = preds["weight"][0].replace("(kilograms)", "kilograms").replace("(kilogram)", "kilograms")
            parts.append(f"weighs {w}")

        # Position
        if "position" in preds:
            parts.append(f"plays as a {preds['position'][0]}")

        # Current club(s)
        clubs = preds.get("club", []) + preds.get("currentclub", [])
        if clubs:
            club_list = ", ".join(clubs[:-1]) + (" and " if len(clubs) > 1 else "") + clubs[-1] if len(clubs) > 1 else clubs[0]
            extra = " ".join(team_extra_info(c) for c in clubs).strip()
            parts.append(f"plays for {club_list}{extra}")

        # Former teams
        if "formerTeam" in preds:
            ft = ", ".join(preds["formerTeam"][:-1]) + (" and " if len(preds["formerTeam"]) > 1 else "") + preds["formerTeam"][-1] if len(preds["formerTeam"]) > 1 else preds["formerTeam"][0]
            extra = " ".join(team_extra_info(t) for t in preds["formerTeam"]).strip()
            parts.append(f"formerly played for {ft}{extra}")

        # Debut team
        if "debutTeam" in preds:
            dt = preds["debutTeam"][0]
            extra = team_extra_info(dt)
            parts.append(f"made his debut with {dt}{extra}")

        # League
        if "league" in preds:
            parts.append(f"competes in the {preds['league'][0]}")

        # Manager / Coach
        if "manager" in preds:
            parts.append(f"is managed by {preds['manager'][0]}")
        if "coach" in preds:
            parts.append(f"is coached by {preds['coach'][0]}")

        # Draft information
        if "draftYear" in preds:
            parts.append(f"was drafted in {preds['draftYear'][0]}")
        if "draftRound" in preds:
            parts.append(f"was selected in round {preds['draftRound'][0]}")
        if "draftPick" in preds:
            parts.append(f"was the {preds['draftPick'][0]}th pick")
        if "draftTeam" in preds:
            parts.append(f"was drafted by {preds['draftTeam'][0]}")

        # Player number
        if "playerNumber" in preds:
            parts.append(f"wears number {preds['playerNumber'][0]}")

        # Youth club, college
        if "youthclub" in preds:
            parts.append(f"started at youth club {preds['youthclub'][0]}")
        if "college" in preds:
            parts.append(f"attended {preds['college'][0]}")

        # Ground / Stadium
        if "ground" in preds:
            parts.append(f"home ground is {preds['ground'][0]}")
        if "stadium" in preds:
            parts.append(f"plays at {preds['stadium'][0]}")

        # Build subject phrase
        if role:
            subject_phrase = f"The {role} {name}"
        else:
            subject_phrase = name

        sentence = f"{subject_phrase} " + ", ".join(parts) + "."
        sentences.append(sentence.strip())

    # If there are leftover subjects that were only objects (e.g., teams without own facts), ignore them.
    if not sentences:
        return ""
    if len(sentences) == 1:
        return sentences[0]
    else:
        return " ".join(sentences)

    # Combine multiple subject sentences into one fluent paragraph
    if not sentences:
        return ""
    if len(sentences) == 1:
        return sentences[0]
    else:
        return " ".join(sentences)

